async (params, browser) => {
  // Search Kaggle datasets
  await browser.open(`https://www.kaggle.com/datasets?search=${params.query}`)

  // Wait for dataset results
  await browser.waitForSelector('a[href*=\'/datasets/\']', 15000)

  // Let results render
  await browser.wait(3000)

  // Scroll for more results
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract dataset results
  const search_results = await browser.evaluate(`const results = []; const seen = new Set(); document.querySelectorAll('a[href*="/datasets/"]').forEach(a => { const href = a.getAttribute('href'); if (!href || !href.match(/\/datasets\/[^/]+\/[^/]+/) || seen.has(href)) return; seen.add(href); const title = a.textContent.trim(); if (!title || title.length > 200 || title.length < 3) return; const parent = a.closest('li') || a.parentElement; const desc = parent ? Array.from(parent.querySelectorAll('span,p')).map(e => e.textContent.trim()).filter(t => t.length > 20 && t !== title).slice(0, 1).join('') : ''; results.push({ title: title.substring(0, 200), url: 'https://www.kaggle.com' + href, description: desc.substring(0, 300) }); }); return { query: '' + params.query + '', result_count: results.length, results: results.slice(0, 15) };`)

  return search_results
}
